import logging
from dspy.streaming.streaming_listener import StreamListener
from litellm import ModelResponseStream, Delta, StreamingChoices

logger = logging.getLogger('test_logger')
logger.setLevel(logging.DEBUG)
records = []
class H(logging.Handler):
    def emit(self, record):
        records.append(record.getMessage())
logger.addHandler(H())

listener = StreamListener(signature_field_name='answer', debug=True, debug_logger=logger)

def mk_chunk(content):
    return ModelResponseStream(choices=[StreamingChoices(delta=Delta(content=content))])

# feed chunks to trigger start detection for ChatAdapter
for tok in ['[[', ' ## answer ## ]]', '\n', 'Hello', ' world!']:
    listener.receive(mk_chunk(tok))

for r in records:
    print(repr(r))
